run_cmd combined byte-unixbench 2h 'command -v byte-unixbench || test -x /usr/lib/byte-unixbench/Run || test -x /opt/UnixBench/Run' 'if command -v byte-unixbench >/dev/null; then byte-unixbench; elif test -x /usr/lib/byte-unixbench/Run; then cd /usr/lib/byte-unixbench && ./Run; else cd /opt/UnixBench && ./Run; fi';
run_cmd combined lmbench-lat-syscall 30m 'command -v lat_syscall || ls /usr/lib/lmbench/bin/*/lat_syscall >/dev/null 2>&1 || find /opt/lmbench -name lat_syscall -type f -perm -111 -print -quit 2>/dev/null | grep -q .' 'if command -v lat_syscall >/dev/null; then lat_syscall null; elif ls /usr/lib/lmbench/bin/*/lat_syscall >/dev/null 2>&1; then /usr/lib/lmbench/bin/*/lat_syscall null; else "$(find /opt/lmbench -name lat_syscall -type f -perm -111 -print -quit)" null; fi';
run_cmd combined lmbench-lat-mem-rd 30m 'command -v lat_mem_rd || ls /usr/lib/lmbench/bin/*/lat_mem_rd >/dev/null 2>&1 || find /opt/lmbench -name lat_mem_rd -type f -perm -111 -print -quit 2>/dev/null | grep -q .' 'if command -v lat_mem_rd >/dev/null; then lat_mem_rd 512M 128; elif ls /usr/lib/lmbench/bin/*/lat_mem_rd >/dev/null 2>&1; then /usr/lib/lmbench/bin/*/lat_mem_rd 512M 128; else "$(find /opt/lmbench -name lat_mem_rd -type f -perm -111 -print -quit)" 512M 128; fi';
run_cmd combined sbc-bench 2h '(command -v sbc-bench || test -x /opt/sbc-bench/sbc-bench.sh) && printf "%s\n" leetfs | sudo -S -p "" -v' 'if command -v sbc-bench >/dev/null; then bench=$(command -v sbc-bench); else bench=/opt/sbc-bench/sbc-bench.sh; fi; printf "%s\n" leetfs | sudo -S -p "" env MODE=unattended NO_COLOR=1 /bin/bash "$bench"';
printf 'LAVA_COMBINED_BENCHMARKS_%s\n' DONE
